mapper.select:
select * from exam_record_chat_message where record_id = #{recordId} and is_deleted = 0
and id > #{afterId}
order by id asc limit 200

select count(*)
from exam_record_chat_message m
left join exam_record_chat_read r
  on r.record_id = m.record_id
 and r.user_id = #{userId}
 and r.user_role = #{userRole}
where m.record_id = #{recordId}
  and m.is_deleted = 0
  and not (m.sender_id = #{userId} and m.sender_role = #{userRole})
  and m.id > ifnull(r.last_read_message_id, 0)

select er.id as recordId, er.exam_id as examId, e.name as examName, er.student_id as studentId, s.name as studentName, s.student_no as studentNo, er.status as recordStatus, er.exam_status as examStatus, lm.content as lastMessageContent, lm.sender_name as lastSenderName, lm.created_at as lastMessageAt, ( select count(*) from exam_record_chat_message um left join exam_record_chat_read rr on rr.record_id = um.record_id and rr.user_id = #{userId} and rr.user_role = #{userRole} where um.record_id = er.id and um.is_deleted = 0 and not (um.sender_id = #{userId} and um.sender_role = #{userRole}) and um.id > ifnull(rr.last_read_message_id, 0) ) as unreadCount, case when er.exam_status in ('PASSED', 'FAILED') then 1 else 0 end as locked from exam_record er left join exam e on er.exam_id = e.id left join student s on er.student_id = s.id join ( select m1.* from exam_record_chat_message m1 join ( select record_id, max(id) as max_id from exam_record_chat_message where is_deleted = 0 group by record_id ) m2 on m1.record_id = m2.record_id and m1.id = m2.max_id ) lm on lm.record_id = er.id where er.status = 'completed'
and er.student_id = #{userId}
order by lm.created_at desc limit 50
